"""Основной сервис: карта расширение → провайдер, get_supported_extensions(), extract()."""from __future__ import annotationsimport threadingfrom typing import TYPE_CHECKINGfrom src.modules.file_discovery.models import DiscoveredDocumentfrom .file_extract_cache import FileExtractCacheServicefrom ..providers.file_extract_provider import (    get_extension_map,    get_supported_extensions as _registry_supported_extensions,)from ..models import (    ExtractedDocument,    ExtractConfig,    SourceDocument,    compute_extract_hash,)if TYPE_CHECKING:    from src.core.logger import SystemLoggerclass FileExtractService:    """Сервис извлечения контента: кэш по хешу, выбор провайдера по расширению, extract с config и saver."""    def __init__(self, logger: SystemLogger | None = None) -> None:        self._extension_map = get_extension_map()        self._logger = logger    @staticmethod    def get_supported_extensions() -> set[str]:        """Объединение всех расширений от всех зарегистрированных провайдеров."""        return _registry_supported_extensions()    def extract(        self,        config: ExtractConfig,        source: SourceDocument,        cancel_event: threading.Event | None = None,    ) -> ExtractedDocument | None:        """        Вычисляет хеш (config + файл), при наличии кэша возвращает загруженный ExtractedDocument.        Иначе выбирает провайдера по расширению. Если тип не поддержан или провайдер отключён — возвращает None.        Иначе создаёт FileExtractCacheService(config, extract_hash), вызывает provider.extract(...), сохраняет в кэш и возвращает результат.        """        if cancel_event is not None and cancel_event.is_set():            return None        doc_hash = compute_extract_hash(config, source.file_hash)        cached = FileExtractCacheService.load_extracted_document(config, doc_hash)        if cached is not None:            # Cache хранит только extract-данные и file_hash; source-метаданные всегда берём из текущего документа.            return ExtractedDocument(                source=DiscoveredDocument(                    path=str(source.path),                    folder=source.folder,                    filename=source.filename,                    extension=source.normalized_extension(),                    mime_type=source.mime_type,                    hash=source.file_hash or cached.source.hash,                ),                config=cached.config,                extract_hash=cached.extract_hash,                content_hash=cached.content_hash,                content=cached.content,            )        ext = source.normalized_extension()        provider = self._extension_map.get(ext)        if provider is None:            if self._logger is not None:                self._logger.warning(                    "Пропуск извлечения: нет провайдера для расширения %s (файл %s)",                    ext,                    source.path,                )            return None        if cancel_event is not None and cancel_event.is_set():            return None        storage = FileExtractCacheService(config, doc_hash)        doc = provider.extract(            source,            config,            storage,            document_hash=doc_hash,            cancel_event=cancel_event,        )        if cancel_event is not None and cancel_event.is_set():            return None        storage.save_extracted_document(doc)        return doc